"""Unified notification service — generated by doql."""
from services.email_service import send_email
from services.slack_service import send_slack


def notify(message: str, recipients: list[str] | None = None, channels: list[str] | None = None):
    """Send notification via all configured channels."""
    results = {}
    if recipients:
        results["email"] = send_email(recipients, "Notification", message)
    results["slack"] = send_slack(message)
    return results
